        }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAPIAuth": []\n          }\n        ]\n      }\n    },\n    "/change-password": {\n      "post": {\n        "operationId": "identity_change_password",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/ChangePasswordRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "default": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          }\n        }\n      }\n    },\n    "/update-profile": {\n      "put": {\n        "operationId": "identity_update_profile",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/UpdateProfileRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/app-details/{client_id_}": {\n      "get": {\n        "operationId": "identity_get_app_by_client_id",\n        "parameters": [\n          {\n            "name": "client_id_",\n            "in": "path",\n            "required