 }\n            }\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/request-password": {\n      "post": {\n        "operationId": "identity_request_password_reset",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/RequestPasswordRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/reset-password": {\n      "post": {\n        "operationId": "identity_reset_password",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/ResetPasswordRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/create-api-token": {\n      "post": {\n        "operationId": "identity_create_api_token",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/CreateApiTokenRequest"\n              }\n            }\n          },\