 "operationId": "identity_get_members",\n        "parameters": [\n          {\n            "name": "group_param",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "array",\n                  "items": {\n                    "$ref": "#/components/schemas/UserInfoResponse"\n                  }\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/manage-membership/{group_param}/{user_id}/{action}": {\n      "put": {\n        "operationId": "identity_manage_membership",\n        "parameters": [\n          {\n            "name": "group_param",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          },\n          {\n            "name": "user_id",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          },\n          {\n            "name": "action",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {}\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/create-api-session-token": {\n      "post": {\n        "operationId": "identity_create_api_session_token",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/CreateSessionTokenRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "default": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/CreateSessionTokenResponse"\n                }\n              }\n            }\n          }\n        }\n      }\n    },\n    "/api-tokens/{group_identifier}": {\n      "get": {\n        "operationId": "identity_get_api_tokens_by_group",\n        "parameters": [\n          {\n            "name": "group_identifier",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "array",\n                  "items": {\n                    "$ref": "#/components/schemas/GroupApiTokenResponse"\n                  }\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/api-tokens/{token_id}/deactivate": {\n      "put": {\n        "operationId": "identity_deactivate_api_token",\n        "parameters": [\n          {\n            "name": "token_id",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "integer",\n              "format": "int64"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/create-api-session-token-interactive/{group_identifier}": {\n      "post": {\n        "description": "this is used by the developers on their machine for creating a session. This assumes that there is an active session on the machine",\n        "operationId": "identity_create_api_session_token_interactive",\n        "parameters": [\n          {\n            "name": "group_identifier",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/CreateSessionTokenResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/clear-redis": {\n      "get": {\n        "operationId": "identity_clear_redis",\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "string"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/get_group_members_ids/{group_identifier}": {\n      "get": {\n        "operationId": "identity_get_group_members_ids",\n        "parameters": [\n          {\n            "name": "group_identifier",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "array",\n                  "items": {\n                    "type": "integer",\n                    "format": "int64"\n                  }\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAPIAuth": []\n          }\n        ]\n      }\n    },\n    "/user-land/get_group_members_ids/{group_identifier}": {\n      "get": {\n        "operationId": "identity_get_group_members_ids_user_land",\n        "parameters": [\n          {\n            "name": "group_identifier",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "array",\n                  "items": {\n                    "type": "integer",\n                    "format": "int64"\n                  }\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/confirm-register/{registration_token}": {\n      "get": {\n        "operationId": "identity_registeration_confirmation",\n        "parameters": [\n          {\n            "name": "registration_token",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "string"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/accept-invite/{invitation_token}": {\n      "post": {\n        "operationId": "identity_accept_invite",\n        "parameters": [\n          {\n            "name": "invitation_token",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/AcceptInviteRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "string"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    },\n    "/accessible-apps": {\n      "get": {\n        "operationId": "identity_get_accessible_apps",\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "type": "array",\n                  "items": {\n                    "$ref": "#/components/schemas/AccessibleApp"\n                  }\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/generate-app-tokens/{app_id}": {\n      "post": {\n        "operationId": "identity_generate_app_tokens",\n        "parameters": [\n          {\n            "name": "app_id",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/LoginResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        },\n        "security": [\n          {\n            "BearerAuth": []\n          }\n        ]\n      }\n    },\n    "/create_or_update_app": {\n      "post": {\n        "operationId": "identity_create_or_update_app",\n        "requestBody": {\n          "content": {\n            "application/json": {\n              "schema": {\n                "$ref": "#/components/schemas/CreateOrUpdateAppRequest"\n              }\n            }\n          },\n          "required": true\n        },\n        "responses": {\n          "201": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/MessageResponse"\n                }\n              }\n            }\n          }\n        },\n        "security": [\n          {\n            "BearerAPIAuth": []\n          }\n        ]\n      }\n    },\n    "/is_member/{group_param}": {\n      "get": {\n        "operationId": "identity_is_member",\n        "parameters": [\n          {\n            "name": "group_param",\n            "in": "path",\n            "required": true,\n            "schema": {\n              "type": "string"\n            }\n          }\n        ],\n        "responses": {\n          "200": {\n            "description": "",\n            "content": {\n              "application/json": {\n                "schema": {\n                  "$ref": "#/components/schemas/IsMemberResponse"\n                }\n              }\n            }\n          },\n          "default": {\n            "description": ""\n          }\n        }\n      }\n    }\n  },\n  "components": {\n    "schemas": {\n      "MessageResponse": {\n        "type": "object",\n        "required": [\n          "message"\n        ],\n        "properties": {\n          "message": {\n            "description": "This is a message from the server.",\n            "type": "string"\n          }\n        }\n      },\n      "RegisterRequest": {\n        "type": "object",\n        "required": [\n          "app_id",\n          "email",\n          "password"\n        ],\n        "properties": {\n          "email": {\n            "type": "string"\n          },\n          "password": {\n            "type": "string"\n          },\n          "app_id": {\n            "type": "string"\n          }\n        }\n      },\n      "IAMLoginResponse": {\n        "type": "object",\n        "required": [\n          "iam_tokens"\n        ],\n        "properties": {\n          "app_tokens": {\n            "allOf": [\n              {\n                "$ref": "#/components/schemas/LoginResponse"\n              }\n            ],\n            "nullable": true\n          },\n          "iam_tokens": {\n            "$ref": "#/components/schemas/LoginResponse"\n          }\n        }\n      },\n      "LoginResponse": {\n        "type": "object",\n        "required": [\n          "access_token",\n          "refresh_token"\n        ],\n        "prope